return [{ json: {
  body: {
    request_id: "test-00000000-0000-0000-0000-000000000001",
    project_id: "pm-lite",
    meeting_id: "test-meeting-001",
    meeting_date: "2026-05-18",
    meeting_title: "Test meeting - sample transcript",
    transcript: "Shane: OK so the main thing today is we need to decide on the email provider - we have Resend currently but it is being deprecated. Options are Gmail SMTP or Postmark. Gmail SMTP is what we use everywhere else. Co-founder: Right, and there is a risk that if we do not switch in the next two weeks, deliverability drops because Resend free tier is throttling. Shane: Agreed. So decision: switch to Gmail SMTP. I will own the migration, target date Friday next week. Co-founder: Also - we noticed in QA that the password reset email is landing on the homepage with an OTP error, not the reset page. Issue I would say high severity. Shane: Yeah, Supabase Auth URL configuration. Known fix. I will do it as part of the same migration. Co-founder: And one more - assumption check: are we sure all tenants want Gmail SMTP, or should we make it configurable per tenant? Shane: Good point, capture as an assumption for now, we will validate with the first two paying tenants. Lesson - every email-provider decision needs a per-tenant configurability check, not just a global default.",
    attendees: ["Shane Burrowes", "Co-founder"],
    source_tool: "manual"
  }
} }];

const items = $input.all();
const out = [];
for (const it of items) {
  const payload = it.json.body || it.json;
  const required = ["request_id", "project_id", "meeting_date", "meeting_title", "source_tool"];
  const missing = required.filter(k => !payload[k]);
  if (missing.length) {
    throw new Error("Missing required fields: " + missing.toString());
  }
  if (!payload.transcript && !payload.minutes_url) {
    throw new Error("Either minutes_url or transcript must be provided");
  }
  if (payload.transcript && payload.minutes_url) {
    throw new Error("Provide minutes_url OR transcript, not both");
  }
  if (!/^\d{4}-\d{2}-\d{2}$/.test(payload.meeting_date)) {
    throw new Error("meeting_date must be YYYY-MM-DD, got: " + payload.meeting_date);
  }
  const allowedSources = ["fireflies", "otter", "granola", "read-ai", "manual"];
  if (!allowedSources.includes(payload.source_tool)) {
    throw new Error("source_tool must be one of " + allowedSources.toString());
  }
  const normalised = Object.assign({}, payload, {
    received_at: new Date().toISOString(),
    workflow_version: "1.0"
  });
  out.push({ json: normalised });
}
return out;

