const claudeResponse = $input.first().json;
const meetingPayload = $("Validate and Normalise").first().json;

const rawText = claudeResponse.content && claudeResponse.content[0] && claudeResponse.content[0].text
  ? claudeResponse.content[0].text
  : (typeof claudeResponse === "string" ? claudeResponse : JSON.stringify(claudeResponse));

const cleaned = rawText.replace(/^\s*```(?:json)?\s*/i, "").replace(/\s*```\s*$/i, "").trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error("Claude returned non-JSON response: " + e.message + "; raw: " + cleaned.substring(0, 500));
}

const entries = parsed.entries || [];
const summary = parsed.summary || "";
const skippedItems = parsed.skipped_items || [];

const prefixMap = {
  risk: "R-",
  issue: "I-",
  decision: "D-",
  dependency: "Dep-",
  assumption: "A-",
  lesson: "L-"
};

const enriched = entries.map((e, idx) => {
  const entryId = prefixMap[e.type] + String(Date.now()).slice(-6) + "-" + String(idx + 1).padStart(2, "0");
  return {
    project_id: meetingPayload.project_id,
    entry_id: entryId,
    type: e.type,
    title: e.title,
    description: e.description,
    status: (e.type === "risk" || e.type === "issue") ? "open" : "active",
    severity: e.severity || null,
    likelihood: e.likelihood || null,
    owner: e.owner || null,
    rationale: e.rationale || null,
    consequences: e.consequences || null,
    action_or_mitigation: e.action_or_mitigation || null,
    opened_date: meetingPayload.meeting_date,
    source_doc: meetingPayload.meeting_title,
    source_url: meetingPayload.minutes_url || null,
    metadata: {
      request_id: meetingPayload.request_id,
      meeting_id: meetingPayload.meeting_id,
      source_tool: meetingPayload.source_tool,
      evidence_quote: e.evidence_quote || "",
      extracted_by: "claude-sonnet-4-5",
      workflow: "meeting-minutes-to-raidd",
      workflow_version: "1.0"
    }
  };
});

const lines = enriched.map((e, i) => (i + 1) + ". [" + e.type.toUpperCase() + "] " + e.title + (e.severity ? " (sev: " + e.severity + ")" : "") + (e.owner ? " - owner: " + e.owner : ""));
const skippedLines = skippedItems.map(s => "- " + s);

const approvalText = "*RAIDD entries from: " + meetingPayload.meeting_title + "*\n\n" +
  "*Project:* " + meetingPayload.project_id + "  *Date:* " + meetingPayload.meeting_date + "\n" +
  "*Source:* " + meetingPayload.source_tool + "\n" +
  "*Attendees:* " + (meetingPayload.attendees || []).toString() + "\n\n" +
  "*Summary:* " + summary + "\n\n" +
  "*Proposed entries (" + enriched.length + "):*\n" +
  lines.toString().replace(/,/g, "\n") +
  (skippedItems.length ? "\n\n*Skipped (not extracted):*\n" + skippedLines.toString().replace(/,/g, "\n") : "");

return [{ json: {
  entries: enriched,
  summary: summary,
  skipped_items: skippedItems,
  approval_text: approvalText,
  entry_count: enriched.length,
  request_id: meetingPayload.request_id,
  project_id: meetingPayload.project_id,
  meeting_title: meetingPayload.meeting_title
} }];
